function jsfShowModal(a,o,l,t){var d={OFSID:a,LNGID:o,PSTID:l};$.when($.ajax({type:"POST",dataType:"json",data:d,url:"/tgpst"})).done(function(a,o,l){var d=a.aRow;0==d.PMDLG?($("#myModalLabel").html(t),$("#myModalBody").html(d.PTEXT),$("#myModal").modal("show")):1==d.PMDLG&&($("#myModalLargeLabel").html(t),$("#myModalLargeBody").html(d.PTEXT),$("#myModalLarge").modal("show"))}).fail(function(a,o,l){alert("錯誤代碼 "+a.status)})}